+{
+    let mut has_r = false;
+    let mut has_f = false;
+    let mut target: Option<&str> = None;
+    let mut options_ended = false;
+
+    for token in tokens {
+        if !options_ended && token == "--" {
+            options_ended = true;
+            continue;
+        }
+        if !options_ended && token.starts_with('-') {
+            if token == "--recursive" {
+                has_r = true;
+                continue;
+            }
+            if token == "--force" {
+                has_f = true;
+                continue;
+            }
